850	function buildBreakdown(r,sf){
851	  const Fs=[r.Fbrk,r.Fstr,r.FbA,r.FbB],descs=[`Su ${r.gr.Su}×As ${r.b.As}`,`τ ${r.threadTau} MPa (${r.hasNut?'ナット':'部材B'})`,`面圧 ${r.bA} MPa`,`面圧 ${r.bB} MPa`];
852	  ['bd0','bd1','bd2','bd3'].forEach((id,i)=>{const isL=Math.abs(Fs[i]-r.Flim)<0.01;ge(id+'v').innerHTML=(Fs[i]/1000).toFixed(2)+'<span class="mc-u">kN</span>';ge(id+'s').textContent=descs[i];ge(id).className='mc '+(isL?'danger':'');ge(id).style.opacity='1';});
853	  ge('bd4v').textContent=r.failMode;ge('bd4').className='mc '+(r.failMode==='ボルト破断'?'ok':'danger');
854	  const bkL=['ボルト破断','山飛び','座面A','座面B'],lims=Fs.map(f=>f/1000),reqs=lims.map(v=>Math.min(v,r.Flim/1000)/sf);
855	  const bkLabelsMulti=bkL.map((label,i)=>[label,`限界時T: ${(Fs[i]*r.denom).toFixed(1)}Nm`,`要求時T: ${(reqs[i]*1000*r.denom).toFixed(1)}Nm`]);
856	  mkC('cMG',{type:'bar',data:{labels:bkLabelsMulti,datasets:[{label:'限界軸力',data:lims,backgroundColor:lims.map((v,i)=>Math.abs(v-r.Flim/1000)<0.01?'#E24B4A':'#85B7EB'),borderWidth:0},{label:'要求軸力 (/S)',data:reqs,backgroundColor:'#C0DD97',borderWidth:0}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:true,position:'top',labels:{font:{size:10},padding:6}},tooltip:{callbacks:{title:i=>bkL[i[0].dataIndex],label:function(ctx){const idx=ctx.dataIndex;const F=parseFloat(ctx.raw).toFixed(2);const margin=(lims[idx]/reqs[idx]).toFixed(2);const isCritical=Math.abs(lims[idx]-r.Flim/1000)<0.01;if(ctx.datasetIndex===0){return[`${ctx.dataset.label}: ${F} kN`,`限界軸力時T: ${(Fs[idx]*r.denom).toFixed(1)} Nm`,isCritical?'⚠ この破損が支配的':''];}else{const reqT=(reqs[idx]*1000*r.denom).toFixed(1);return[`${ctx.dataset.label}: ${F} kN`,`要求軸力時T: ${reqT} Nm`,`安全率: ${sf}`,`余裕度: ${margin}x`];}},afterLabel:function(ctx){const idx=ctx.dataIndex;const modes=['ボルト材料の引張強さ Su','めねじ材料のせん断強さ','座面陥没（接触面圧超過）','座面陥没（接触面圧超過）'];return `破損メカニズム: ${modes[idx]}`;}},backgroundColor:'rgba(0,0,0,0.85)',titleFont:{size:11,weight:'bold'},bodyFont:{size:10},padding:10}},scales:{x:{ticks:{font:{size:9}}},y:{title:{display:true,text:'軸力 (kN)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'}}}});
857	  const bkLL=['ボルト破断',`山飛び（${r.hasNut?'ナット':'部材B'}）`,'座面陥没 A面','座面陥没 B面'];
858	  const recTorque=r.T_lim?r.T_lim/sf:null;
859	  ge('bd-tbl').innerHTML=bkLL.map((l,i)=>{
860	    const isL=Math.abs(Fs[i]-r.Flim)<0.01;
861	    const mg=(Fs[i]/1000)/(r.Flim/1000/sf);
862	    const tl=Fs[i]*r.denom;
863	    const reqT=(Fs[i]*r.denom/sf).toFixed(1);
864	    const isDanger=recTorque&&tl<recTorque;
