function buildBreakdown(r,sf){
  const Fs=[r.Fbrk,r.Fstr,r.FbA,r.FbB],descs=[`Su ${r.gr.Su}×As ${r.b.As}`,`τ ${r.threadTau} MPa (${r.hasNut?'ナット':'部材B'})`,`面圧 ${r.bA} MPa`,`面圧 ${r.bB} MPa`];
  ['bd0','bd1','bd2','bd3'].forEach((id,i)=>{const isL=Math.abs(Fs[i]-r.Flim)<0.01;ge(id+'v').innerHTML=(Fs[i]/1000).toFixed(2)+'<span class="mc-u">kN</span>';ge(id+'s').textContent=descs[i];ge(id).className='mc '+(isL?'danger':'');ge(id).style.opacity='1';});
  ge('bd4v').textContent=r.failMode;ge('bd4').className='mc '+(r.failMode==='ボルト破断'?'ok':'danger');
  const bkL=['ボルト破断','山飛び','座面A','座面B'],lims=Fs.map(f=>f/1000),reqs=lims.map(v=>Math.min(v,r.Flim/1000)/sf);
  const bkLabelsMulti=bkL.map((label,i)=>[label,`限界時T: ${(Fs[i]*r.denom).toFixed(1)}Nm`,`要求時T: ${(reqs[i]*1000*r.denom).toFixed(1)}Nm`]);
  mkC('cMG',{type:'bar',data:{labels:bkLabelsMulti,datasets:[{label:'限界軸力',data:lims,backgroundColor:lims.map((v,i)=>Math.abs(v-r.Flim/1000)<0.01?'#E24B4A':'#85B7EB'),borderWidth:0},{label:'要求軸力 (/S)',data:reqs,backgroundColor:'#C0DD97',borderWidth:0}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:true,position:'top',labels:{font:{size:10},padding:6}},tooltip:{callbacks:{title:i=>bkL[i[0].dataIndex],label:function(ctx){const idx=ctx.dataIndex;const F=parseFloat(ctx.raw).toFixed(2);const margin=(lims[idx]/reqs[idx]).toFixed(2);const isCritical=Math.abs(lims[idx]-r.Flim/1000)<0.01;if(ctx.datasetIndex===0){return[`${ctx.dataset.label}: ${F} kN`,`限界軸力時T: ${(Fs[idx]*r.denom).toFixed(1)} Nm`,isCritical?'⚠ この破損が支配的':''];}else{const reqT=(reqs[idx]*1000*r.denom).toFixed(1);return[`${ctx.dataset.label}: ${F} kN`,`要求軸力時T: ${reqT} Nm`,`安全率: ${sf}`,`余裕度: ${margin}x`];}},afterLabel:function(ctx){const idx=ctx.dataIndex;const modes=['ボルト材料の引張強さ Su','めねじ材料のせん断強さ','座面陥没（接触面圧超過）','座面陥没（接触面圧超過）'];return `破損メカニズム: ${modes[idx]}`;}},backgroundColor:'rgba(0,0,0,0.85)',titleFont:{size:11,weight:'bold'},bodyFont:{size:10},padding:10}},scales:{x:{ticks:{font:{size:9}}},y:{title:{display:true,text:'軸力 (kN)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'}}}});
  const bkLL=['ボルト破断',`山飛び（${r.hasNut?'ナット':'部材B'}）`,'座面陥没 A面','座面陥没 B面'];
  const recTorque=r.T_lim?r.T_lim/sf:null;
  ge('bd-tbl').innerHTML=bkLL.map((l,i)=>{
    const isL=Math.abs(Fs[i]-r.Flim)<0.01;
    const mg=(Fs[i]/1000)/(r.Flim/1000/sf);
    const tl=Fs[i]*r.denom;
    const reqT=(Fs[i]*r.denom/sf).toFixed(1);
    const isDanger=recTorque&&tl<recTorque;
    const torqueStyle=isDanger?'color:#E24B4A;font-weight:bold':isL?'color:#E24B4A;font-weight:bold':'';
    const rowStyle=isL?'background:#FFF5F5':'';
    return `<tr style="${rowStyle}"><td style="${isL?'font-weight:bold':''}"><span style="margin-right:4px">${isL?'⚠':''}</span>${l}</td><td>${(Fs[i]/1000).toFixed(2)}</td><td style="${torqueStyle}">${tl.toFixed(1)}${isDanger?' ⚠':''}</td><td>${reqT}</td><td style="${mg<1.2?'color:#A32D2D':mg<1.5?'color:#854F0B':'color:#3B6D11'}">${mg.toFixed(2)}x</td><td>${isL?'<span class="sb2 s-l">支配的</span>':'—'}</td></tr>`;
  }).join('');
}
function buildJoint(r,sf,fext){
  const s=r.stiff;
  ge('jt-kb').textContent=(s.kb/1000).toFixed(0)+' kN/mm';ge('jt-kc').textContent=(s.kc/1000).toFixed(0)+' kN/mm';ge('jt-phi').textContent=s.phi.toFixed(4);
  const Fi=r.T_lim?(r.T_lim/sf)/r.denom*1000:r.Flim/sf,half=Math.abs(fext)||Fi*0.5,Fext_range=Array.from({length:21},(_,i)=>(i-10)*half/10);
  mkC('cJT',{type:'line',data:{datasets:[{label:'ボルト軸力',data:Fext_range.map(fe=>({x:fe/1000,y:(Fi+s.phi*fe)/1000})),borderColor:'#185FA5',backgroundColor:'transparent',borderWidth:2,pointRadius:0},{label:'残留締付力',data:Fext_range.map(fe=>({x:fe/1000,y:Math.max(0,(Fi-(1-s.phi)*fe)/1000)})),borderColor:'#1D9E75',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[4,2]},{label:'初期Fi',data:[{x:Fext_range[0]/1000,y:Fi/1000},{x:Fext_range[20]/1000,y:Fi/1000}],borderColor:'#888',backgroundColor:'transparent',borderWidth:1,pointRadius:0,borderDash:[3,3]}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false}},scales:{x:{type:'linear',title:{display:true,text:'外部軸力 Fext (kN)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'},y:{title:{display:true,text:'軸力 (kN)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'}}}});
  const phiArr=Array.from({length:21},(_,i)=>+(i*0.05).toFixed(2));
  mkC('cPH',{type:'line',data:{datasets:[{label:'ボルト負担',data:phiArr.map(p=>({x:p,y:p})),borderColor:'#185FA5',backgroundColor:'transparent',borderWidth:2,pointRadius:0},{label:'部材負担',data:phiArr.map(p=>({x:p,y:1-p})),borderColor:'#1D9E75',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[4,2]},{label:'現在Φ',data:[{x:s.phi,y:0},{x:s.phi,y:1}],borderColor:'#E24B4A',backgroundColor:'transparent',borderWidth:1.5,pointRadius:0,borderDash:[3,3]}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false}},scales:{x:{type:'linear',min:0,max:1,title:{display:true,text:'剛性比 Φ',font:{size:9}},ticks:{font:{size:9}}},y:{min:0,max:1,title:{display:true,text:'外力分担割合',font:{size:9}},ticks:{font:{size:9}}}}}});
  ge('jt-tbl').innerHTML=[
    ['初期締付力 Fi',`${(Fi/1000).toFixed(2)} kN`,`推奨T ${r.T_lim?(r.T_lim/sf).toFixed(1):'—'} Nm 締付時`],
    ['ボルト剛性 kb',`${(s.kb/1000).toFixed(0)} kN/mm`,`E=${r.Eb} GPa, As=${r.b.As} mm², Lg=${r.Lg} mm`],
    ['被締結部材 A 剛性',`${(s.kca/1000).toFixed(0)} kN/mm`,`${CL_MAT[r.cmA].name}, t=${r.tA} mm`],
    ['被締結部材 B 剛性',`${(s.kcb/1000).toFixed(0)} kN/mm`,`${CL_MAT[r.cmB].name}, t=${r.tB} mm`],
    ['合成部材剛性 kc',`${(s.kc/1000).toFixed(0)} kN/mm`,'1/(1/kca + 1/kcb)'],
    ['剛性比 Φ',s.phi.toFixed(4),'Φ < 0.1 が推奨'],
    ['外部軸力のΔFb',`${(s.phi*(fext||0)/1000).toFixed(2)} kN`,`Fext = ${fext} N`],
    ['残留締付力',`${Math.max(0,(Fi-(1-s.phi)*(fext||0))/1000).toFixed(2)} kN`,'0以上を確認（開口防止）']
  ].map(([a,b,c])=>`<tr><td>${a}</td><td>${b}</td><td style="color:#888">${c}</td></tr>`).join('');
}
function switchTab(name){
  curTab=name;
  ['graph','table','breakdown','joint','fatigue'].forEach(n=>{ge('tab-'+n).className='tab'+(n===name?' on':'');ge('pane-'+n).style.display=n===name?'':'none';});
  const sf=+gv('safety'),fext=+gv('f_ext');
  if(name==='graph')drawGraphs(RES,RES2,sf);
  else if(name==='table')buildTable(RES);
  else if(name==='breakdown')buildBreakdown(RES,sf);
  else if(name==='joint')buildJoint(RES,sf,fext);
  else buildFatigue(RES,sf);
}
function toggleCmp(){ge('caseb').style.display=ge('cmp_on').checked?'':'none';calc()}
function toggleLegendItem(elem){const chartId=elem.dataset.chart,idx=+elem.dataset.index,chart=CH[chartId];if(!chart)return;const meta=chart.getDatasetMeta(idx);meta.hidden=meta.hidden===null?!chart.data.datasets[idx].hidden:!meta.hidden;chart.update();elem.classList.toggle('hidden',meta.hidden)}

