919	function buildBreakdown(r,sf){
920	  const Fs=[r.Fbrk,r.Fstr,r.FbA,r.FbB],descs=[`Su ${r.gr.Su}×As ${r.b.As}`,`τ ${r.threadTau} MPa (${r.hasNut?'ナット':'部材B'})`,`面圧 ${r.bA} MPa`,`面圧 ${r.bB} MPa`];
921	  const labels=['ボルト破断',`山飛び（${r.hasNut?'ナット':'部材B'}）`,'座面陥没 A','座面陥没 B'];
922	  const cardData=[{id:'bd0',label:labels[0],F:Fs[0],desc:descs[0]},{id:'bd1',label:labels[1],F:Fs[1],desc:descs[1]},{id:'bd2',label:labels[2],F:Fs[2],desc:descs[2]},{id:'bd3',label:labels[3],F:Fs[3],desc:descs[3]}].sort((a,b)=>a.F-b.F);
923	  const container=ge('bd-cards');
924	  cardData.forEach((card,idx)=>{const elem=ge(card.id);const isL=Math.abs(card.F-r.Flim)<0.01;const torque=(card.F*r.denom).toFixed(1);elem.querySelector('.mc-l').textContent=card.label;elem.querySelector('.mc-v').innerHTML='限界トルク '+torque+'<span class="mc-u">Nm</span>';ge(card.id+'s').textContent=card.desc;elem.className='mc';elem.style.opacity='1';container.appendChild(elem);});
925	  ge('bd4v').textContent=r.failMode;ge('bd4').className='mc';
926	  const bkData=[{name:'ボルト破断',F:Fs[0],desc:'ボルト材料の引張強さ Su',origIdx:0},{name:`山飛び（${r.hasNut?'ナット':'部材B'}）`,F:Fs[1],desc:'めねじ材料のせん断強さ',origIdx:1},{name:'座面陥没A',F:Fs[2],desc:'座面陥没（接触面圧超過）',origIdx:2},{name:'座面陥没B',F:Fs[3],desc:'座面陥没（接触面圧超過）',origIdx:3}].sort((a,b)=>a.F-b.F);
927	  const bkL=bkData.map(d=>d.name),lims=bkData.map(d=>d.F),reqs=lims.map(v=>Math.min(v,r.Flim)/sf),bkModes=bkData.map(d=>d.desc),origFs=bkData.map(d=>Fs[d.origIdx]);
928	  const limTorques=origFs.map(f=>f*r.denom),reqTorques=reqs.map(f=>f*r.denom);
929	  const barLabelPlugin={id:'barLabels',afterDatasetsDraw(chart){const{ctx,chartArea,scales}=chart;ctx.save();ctx.font='9px sans-serif';ctx.textAlign='center';chart.data.datasets.forEach((dataset,dsIdx)=>{const meta=chart.getDatasetMeta(dsIdx);if(meta.hidden)return;meta.data.forEach((bar,idx)=>{const x=bar.x;const y=chartArea.bottom+8;const torque=dsIdx===0?limTorques[idx]:reqTorques[idx];const label=dsIdx===0?'限界トルク':'推奨トルク';ctx.fillStyle='#666';ctx.fillText(`${label}: ${torque.toFixed(1)}Nm`,x,y);});});ctx.restore();}};
930	  mkC('cMG',{type:'bar',data:{labels:bkL,datasets:[{label:'限界トルク',data:lims,backgroundColor:'#FF9999',borderWidth:0},{label:'推奨トルク',data:reqs,backgroundColor:'#C0DD97',borderWidth:0}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10,bottom:14}},plugins:{legend:{display:true,position:'top',labels:{font:{size:10},padding:6}},tooltip:{callbacks:{title:i=>bkL[i[0].dataIndex],label:function(ctx){const idx=ctx.dataIndex;const F=parseFloat(ctx.raw).toFixed(0);const margin=(lims[idx]/reqs[idx]).toFixed(2);if(ctx.datasetIndex===0){return[`${ctx.dataset.label}: ${F} N`,`締め付けトルク: ${limTorques[idx].toFixed(1)} Nm`];}else{return[`${ctx.dataset.label}: ${F} N`,`締め付けトルク: ${reqTorques[idx].toFixed(1)} Nm`,`安全率: ${sf}`,`余裕度: ${margin}x`];}},afterLabel:function(ctx){const idx=ctx.dataIndex;return `破損メカニズム: ${bkModes[idx]}`;}},backgroundColor:'rgba(0,0,0,0.85)',titleFont:{size:11,weight:'bold'},bodyFont:{size:10},padding:10}},scales:{x:{ticks:{font:{size:11,weight:'bold'},padding:8}},y:{title:{display:true,text:'軸力 (N)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'}}},plugins:[barLabelPlugin]});
931	  const bkLLBase=['ボルト破断',`山飛び（${r.hasNut?'ナット':'部材B'}）`,'座面陥没 A面','座面陥没 B面'];
932	  const bkTblData=[{label:bkLLBase[0],F:Fs[0]},{label:bkLLBase[1],F:Fs[1]},{label:bkLLBase[2],F:Fs[2]},{label:bkLLBase[3],F:Fs[3]}].sort((a,b)=>a.F-b.F);
