934	  ge('bd-tbl').innerHTML=bkTblData.map((d,i)=>{
935	    const isL=Math.abs(d.F-r.Flim)<0.01;
936	    const mg=d.F/(r.Flim/sf);
937	    const tl=d.F*r.denom;
938	    const reqT=(d.F*r.denom/sf).toFixed(1);
939	    const isDanger=recTorque&&tl<recTorque;
940	    const torqueStyle=isDanger?'color:#E24B4A;font-weight:bold':isL?'color:#E24B4A;font-weight:bold':'';
941	    const rowStyle=isL?'background:#FFF5F5':'';
942	    return `<tr style="${rowStyle}"><td style="${isL?'font-weight:bold':''}">${d.label}</td><td>${d.F.toFixed(0)}</td><td style="${torqueStyle}">${tl.toFixed(1)}${isDanger?' ⚠':''}</td><td>${reqT}</td><td style="${mg<1.2?'color:#A32D2D':mg<1.5?'color:#854F0B':'color:#3B6D11'}">${mg.toFixed(2)}x</td><td>${isL?'<span class="sb2 s-l">支配的</span>':'—'}</td></tr>`;
943	  }).join('');
