  const isDanger=recTorque&&tl<recTorque;
  const torqueStyle=isDanger?'color:#E24B4A;font-weight:bold':isL?'color:#E24B4A;font-weight:bold':'';
  const rowStyle=isL?'background:#FFF5F5':'';
  return `<tr style="${rowStyle}"><td style="${isL?'font-weight:bold':''}">${d.label}</td><td>${d.F.toFixed(0)}</td><td style="${torqueStyle}">${tl.toFixed(1)}${isDanger?' ⚠':''}</td><td>${reqT}</td><td style="${mg<1.2?'color:#A32D2D':mg<1.5?'color:#854F0B':'color:#3B6D11'}">${mg.toFixed(2)}x</td><td>${isL?'<span class="sb2 s-l">支配的</span>':'—'}</td></tr>`;
}).join('');

